import 'package:flutter/material.dart'; import 'package:dhv_lingoo/config/theme.dart'; class PrimaryButton extends StatelessWidget { final String label; final VoidCallback? onPressed; final bool loading; const PrimaryButton({super.key, required this.label, this.onPressed, this.loading=false}); @override Widget build(BuildContext context) => SizedBox(width: double.infinity, height: 48, child: ElevatedButton(onPressed: loading ? null : onPressed, style: ElevatedButton.styleFrom(backgroundColor: AppTheme.primary), child: loading ? const SizedBox(width:20,height:20,child:CircularProgressIndicator(strokeWidth:2,color:Colors.white)) : Text(label, style: const TextStyle(fontWeight: FontWeight.w700, color: Colors.white)))); }
